import{_ as a,M as n,p as t,q as o,R as e,t as l,N as r,a1 as s}from"./framework-5866ffd3.js";const d={},c=s('<h1 id="ข้อกําหนดในการใช้งานกลุ่ม" tabindex="-1"><a class="header-anchor" href="#ข้อกําหนดในการใช้งานกลุ่ม" aria-hidden="true">#</a> ข้อกำหนดในการใช้งานกลุ่ม</h1><p>อัปเดทล่าสุด 5 April 2022 <br> เริ่มใช้งานข้อกำหนด June 16, 2021 12:00 AM</p><div class="custom-container tip"><p class="custom-container-title">TL;dr</p><p>☝ ข้อกำหนดนี้ถูกสร้างขึ้นเพื่อให้ผู้ใช้งานกลุ่ม Language: Thai สามารถอยู่ร่วมกันได้และสามารถแชร์มุมมองและประสบการณ์ ไอเดีย และข้อมูล</p></div><h2 id="คําจํากัดความ" tabindex="-1"><a class="header-anchor" href="#คําจํากัดความ" aria-hidden="true">#</a> คำจำกัดความ</h2><ol><li>&quot;ข้อความ&quot; หมายถึงข้อความในรูปแบบตัวอักษร (Text Message), รูปแบบเสียง (Voice Message), รูปแบบวิดีโอ (Video Message) รวมไปถึงการส่งสติกเกอร์ (Sticker), อิโมจิ (Emoji) รวมไปถึงลิงก์แนบ (Shared Link) และไฟล์แนบ (Files)</li><li>&quot;แอดมิน&quot; หมายถึงผู้ดูแลกลุ่มที่ได้รับการแต่งตั้งจากเจ้าของกลุ่ม &#39;Telegram (@telegram)&#39; ทั้งหมด</li></ol><h2 id="สิ่งที่ควรทํา" tabindex="-1"><a class="header-anchor" href="#สิ่งที่ควรทํา" aria-hidden="true">#</a> สิ่งที่ควรทำ</h2><ol><li>ให้เกียรติกับผู้ใช้งานทุกคนในกลุ่ม</li><li>ไม่ส่งลิงก์ที่ไม่มี Preview เนื้อหาภายในลิงก์ <ul><li>กรุณาลบข้อความที่ไม่มี Preview ออกจากข้อความของกลุ่มและส่งข้อความใหม่</li></ul></li><li>แนะนำเพื่อนหรือผู้ใช้งานอื่นให้เข้าร่วมกลุ่มเพื่อแบ่งปันประสบการณ์และความรู้ที่เกี่ยวข้องกับกลุ่ม</li><li>ช่วยรักษาความเป็นระเบียบและสร้างบรรยากาศที่เป็นกันเองสำหรับกลุ่ม</li><li>ใช้ช่องโหว่ของข้อกำหนดนี้ในการแสดงตัวอย่างและการพัฒนาข้อกำหนดการใช้งานกลุ่มต่อไป</li></ol><h2 id="ข้อกําหนด" tabindex="-1"><a class="header-anchor" href="#ข้อกําหนด" aria-hidden="true">#</a> ข้อกำหนด</h2><p>เมื่อผู้ใช้งานเข้าร่วมกลุ่มแปลภาษา Telegram (ภาษาไทย) จะต้องปฏิบัติตามเงื่อนไขดังต่อไปนี้:</p><ol><li>ห้ามส่งข้อความเพื่อทำการก่อกวน เบี่ยงเบน สร้างความสับสน หรือส่งสแปมในกลุ่ม</li><li>ห้ามโพสต์สิ่งที่ไม่เหมาะสมหรือไม่เหมาะสมกับกลุ่ม ไม่อนุญาตให้โฆษณาสินค้าหรือบริการในกลุ่ม ห้ามส่งสแปมหรือโพสต์ข้อความที่ไม่เกี่ยวข้องกับกลุ่ม</li><li>ห้ามเขียนข้อความที่หมิ่นประมาทหรือดูถูกบุคคล กลุ่มคน เชื้อชาติ ศาสนา เพศ หรือมุมมองต่างๆ และห้ามเขียนข้อความเพื่อลดคุณค่าของผู้อื่น</li><li>ห้ามเขียนข้อความที่แสดงถึงหรือสร้างความเกลียดชังและความรุนแรง</li><li>ห้ามกล่าวหาผู้อื่นโดยไม่มีหลักฐานหรือใช้หลักฐานบิดเบือน</li><li>ห้ามส่งลิงก์เชิญไปยังกลุ่ม Telegram อื่นที่ไม่เกี่ยวข้อง</li><li>ห้ามส่งเนื้อหาที่ไม่เกี่ยวข้องกับการแปลภาษาไทยบน Telegram</li><li>ทำการบันทึกเสียง, ข้อความ, วิดีโอ, และ ข้อความวิดีโอ โดยไม่ได้รับการอนุญาติจากผู้ใช้งานในกลุ่มหรือแอดมิน โดยแอดมินจะสามารถอนุมัติได้หากเป็นการบันทึกเพื่อป้องกันตัวเองหากมีการโจมตีหรือคุกคามเกิดขึ้นภายในกลุ่มหรือมีคำสั่งจากหมายศาลเท่านั้น</li></ol><p>หากผิดเงื่อนไขดังต่อไปนี้และมีผู้ใช้งานท่านใดท่านหนึ่งพบเห็น ผู้ใช้นั้นจะถูกลงโทษในทันที โดยแอดมินสามารถดำเนินการได้ทันทีหากพบเห็นหรือได้รับแจ้ง <strong>คำตัดสินของแอดมิน/กลุ่มแอดมินถือเป็นที่สิ้นสุด</strong></p><p>โดยข้อกำหนดข้างต้นทั้งหมด ผู้กระทำความผิดสามารถโต้แย้งแอดมินได้ หากเป็นการฝ่าฝืนข้อกำหนดที่อาจก่อให้เกิดประโยชน์ส่วนรวมหรือเพื่อสร้างความตระหนักให้กับส่วนรวม</p><p>หากผู้ใช้งานเข้าข่ายผิดใน พรบ. คอมพิวเตอร์หรือกฏหมายอื่นที่เกี่ยวข้อง เราอาจจะต้องลบข้อความ สติกเกอร์ อิโมจิ ลิงก์ หรืออื่นๆ เพื่อป้องกันการมีภาระผูกพันกับผู้ใช้ภายในกลุ่ม</p><h2 id="ข้อบังคับหากฝ่าฝืน" tabindex="-1"><a class="header-anchor" href="#ข้อบังคับหากฝ่าฝืน" aria-hidden="true">#</a> ข้อบังคับหากฝ่าฝืน</h2><p>หากผู้ใช้งานฝ่าฝืนจริง แอดมินจะดำเนินการ</p><ol><li>ลบข้อความทั้งหมดที่ฝ่าฝืน (หรือข้อความทั้งหมด หากมีหลายข้อความ)</li></ol><p>และอาจลงโทษผู้ใช้งานดังนี้</p>',17),h=e("li",null,"หากทำผิดครั้งแรก เตะออกจากกลุ่มชั่วคราว (แต่สามารถกลับเข้ากลุ่มได้ตามปกติ)",-1),u=e("li",null,"หากทำผิดครั้งที่สอง แบนการแชท 1 สัปดาห์",-1),_={href:"http://translations.telegram.org",target:"_blank",rel:"noopener noreferrer"},p=e("p",null,[e("strong",null,"แบนการแชท")],-1),g=e("p",null,"ผู้ใช้งานที่ถูกแบนการแชทจะไม่สามารถ",-1),m=e("ul",null,[e("li",null,"ส่งข้อความ"),e("li",null,"ส่งลิงก์หรือไฟล์"),e("li",null,"ส่งโพล์")],-1),f=e("p",null,"แต่ผู้ใช้งานที่ถูกแบนยังคงสามารถ",-1),x=e("ul",null,[e("li",null,"เชิญผู้ใช้งานเข้ากลุ่ม"),e("li",null,"เข้า-ออกจากกลุ่ม")],-1);function T(b,k){const i=n("ExternalLinkIcon");return t(),o("div",null,[c,e("ol",null,[h,u,e("li",null,[l("หากทำผิดครั้งที่สาม เตะออกจากกลุ่มและแบนจากการแปลภาษาไทยบน "),e("a",_,[l("translations.telegram.org"),r(i)]),l(" และเข้ากลุ่มถาวร")])]),p,g,m,f,x])}const V=a(d,[["render",T],["__file","index.html.vue"]]);export{V as default};
